217	func (s *Store) readLegacyRuns() ([]RunRecord, error) {
218		entries, err := os.ReadDir(s.RunsDir)
219		if err != nil {
220			if os.IsNotExist(err) {
221				return nil, nil
222			}
223			return nil, err
224		}
225	
226		records := make([]RunRecord, 0, len(entries))
227		for _, entry := range entries {
228			if !entry.IsDir() || strings.HasPrefix(entry.Name(), ".tmp-") {
229				continue
230			}
231			rec, err := s.readRunBundle(filepath.Join(s.RunsDir, entry.Name()))
232			if err != nil {
233				return nil, err
234			}
235			records = append(records, rec)
236		}
237		return records, nil
238	}
239	
240	func (s *Store) loadRunByID(runID string) (RunRecord, error) {
241		if s.RunCollection != nil {
242			beads, err := s.RunCollection.ReadAll()
243			if err != nil {
244				return RunRecord{}, err
245			}
246			for _, entry := range beads {
247				if entry.ID != runID {
248					continue
249				}
250				return s.runRecordFromBead(entry)
251			}
252		}
253		return s.readRunBundle(filepath.Join(s.RunsDir, runID))
254	}
