256	func definitionBead(def Definition) bead.Bead {
257		title := def.ID
258		if len(def.ArtifactIDs) > 0 {
259			title = fmt.Sprintf("Execution definition for %s", strings.Join(def.ArtifactIDs, ", "))
260		}
261		status := bead.StatusClosed
262		if def.Active {
263			status = bead.StatusOpen
264		}
265		return bead.Bead{
266			ID:        def.ID,
267			Title:     title,
268			Status:    status,
269			Priority:  2,
270			IssueType: "exec_definition",
271			CreatedAt: def.CreatedAt,
272			UpdatedAt: def.CreatedAt,
273			Labels:    definitionLabels(def),
274			Extra: map[string]any{
275				"definition": def,
276			},
277		}
278	}
279	
280	func definitionFromBead(b bead.Bead) (Definition, error) {
281		var def Definition
282		if raw, ok := b.Extra["definition"]; ok {
283			if err := decodeAny(raw, &def); err != nil {
284				return Definition{}, err
285			}
286		}
287		if def.ID == "" {
288			def.ID = b.ID
289		}
290		if def.CreatedAt.IsZero() {
291			def.CreatedAt = b.CreatedAt
292		}
293		if !def.Active {
294			def.Active = b.Status == bead.StatusOpen
295		}
296		if len(def.ArtifactIDs) == 0 {
297			def.ArtifactIDs = beadArtifactIDs(b)
298		}
299		return def, nil
300	}
301	
302	func runBead(rec RunRecord) bead.Bead {
303		title := rec.RunID
304		if len(rec.ArtifactIDs) > 0 {
305			title = fmt.Sprintf("Execution run for %s", strings.Join(rec.ArtifactIDs, ", "))
306		}
307		return bead.Bead{
308			ID:        rec.RunID,
309			Title:     title,
310			Status:    bead.StatusClosed,
311			Priority:  2,
312			IssueType: "exec_run",
313			CreatedAt: rec.StartedAt,
314			UpdatedAt: rec.FinishedAt,
315			Labels:    runLabels(rec),
316			Extra: map[string]any{
317				"manifest": rec.RunManifest,
318			},
319		}
320	}
321	
322	func (s *Store) runRecordFromBead(b bead.Bead) (RunRecord, error) {
323		var manifest RunManifest
324		if raw, ok := b.Extra["manifest"]; ok {
325			if err := decodeAny(raw, &manifest); err != nil {
326				return RunRecord{}, err
327			}
328		}
329		if manifest.RunID == "" {
330			manifest.RunID = b.ID
331		}
332		if len(manifest.ArtifactIDs) == 0 {
333			manifest.ArtifactIDs = beadArtifactIDs(b)
334		}
335		if manifest.StartedAt.IsZero() {
336			manifest.StartedAt = b.CreatedAt
337		}
338		if manifest.FinishedAt.IsZero() {
339			manifest.FinishedAt = b.UpdatedAt
340		}
341		if manifest.Status == "" {
342			manifest.Status = beadRunStatus(b.Status)
343		}
344		if manifest.Attachments == nil {
345			manifest.Attachments = runAttachmentRefs(s.WorkingDir, manifest.RunID)
346		}
347	
348		result, err := s.readRunResult(manifest)
349		if err != nil {
350			return RunRecord{}, err
351		}
352		return RunRecord{RunManifest: manifest, Result: result}, nil
353	}
354	
355	func (s *Store) readRunResult(manifest RunManifest) (RunResult, error) {
356		resultPath := attachmentPath(s.WorkingDir, manifest.Attachments["result"])
357		if resultPath != "" {
358			if raw, err := os.ReadFile(resultPath); err == nil {
359				var result RunResult
360				if err := json.Unmarshal(raw, &result); err != nil {
361					return RunResult{}, err
362				}
363				return result, nil
364			}
365		}
366		resultPath = filepath.Join(s.runBundleDir(manifest.RunID), "result.json")
367		raw, err := os.ReadFile(resultPath)
368		if err != nil {
369			return RunResult{}, err
370		}
371		var result RunResult
372		if err := json.Unmarshal(raw, &result); err != nil {
373			return RunResult{}, err
374		}
375		return result, nil
376	}
