482	func (s *Store) runBundleDir(runID string) string {
483		return filepath.Join(s.WorkingDir, ".ddx", execRunAttachmentDir, runID)
484	}
485	
486	func runAttachmentRef(workingDir, runID, name string) string {
487		return filepath.Join(execRunAttachmentDir, runID, name)
488	}
489	
490	func runAttachmentRefs(workingDir, runID string) map[string]string {
491		return map[string]string{
492			"stdout": runAttachmentRef(workingDir, runID, "stdout.log"),
493			"stderr": runAttachmentRef(workingDir, runID, "stderr.log"),
494			"result": runAttachmentRef(workingDir, runID, "result.json"),
495		}
496	}
497	
498	func attachmentPath(workingDir, ref string) string {
499		if ref == "" {
500			return ""
501		}
502		if filepath.IsAbs(ref) {
503			return ref
504		}
505		return filepath.Join(workingDir, ".ddx", filepath.FromSlash(ref))
506	}
507	
508	func beadRunStatus(status string) string {
509		switch status {
510		case StatusSuccess:
511			return "success"
512		case StatusTimedOut:
513			return "timed_out"
514		case StatusErrored:
515			return "errored"
516		default:
517			return "failed"
518		}
519	}
